import{_ as i,o as a,c as e,a9 as r}from"./chunks/framework.STMWz9Nm.js";const b=JSON.parse('{"title":"Rust Web 错误处理与中间件设计","description":"","frontmatter":{},"headers":[],"relativePath":"语言/Rust/01-Rust语言基础与核心机制/22-Rust Web错误处理与中间件设计.md","filePath":"语言/Rust/01-Rust语言基础与核心机制/22-Rust Web错误处理与中间件设计.md","lastUpdated":1777177198000}'),h={name:"语言/Rust/01-Rust语言基础与核心机制/22-Rust Web错误处理与中间件设计.md"};function t(n,l,s,d,o,u){return a(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="rust-web-错误处理与中间件设计" tabindex="-1">Rust Web 错误处理与中间件设计 <a class="header-anchor" href="#rust-web-错误处理与中间件设计" aria-label="Permalink to “Rust Web 错误处理与中间件设计”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>当你已经会写 Axum 或 Actix Web 的基础路由后，下一步很快就会遇到两个工程问题：</p><ul><li>错误怎么统一处理</li><li>横切逻辑应该放在哪里</li></ul><p>这篇讲的就是这两件事：</p><ul><li><strong>错误处理</strong>：请求失败后，应该怎样稳定、清晰地对外表达</li><li><strong>中间件设计</strong>：日志、鉴权、请求追踪、限流、上下文注入这类横切逻辑，应该怎样组织</li></ul><p>一句话理解：</p><ul><li>handler 负责处理当前请求的业务入口</li><li>错误处理负责定义失败语义</li><li>中间件负责承载跨多个路由共享的横切规则</li></ul><h2 id="_2-为什么这两个主题总会一起出现" tabindex="-1">2. 为什么这两个主题总会一起出现 <a class="header-anchor" href="#_2-为什么这两个主题总会一起出现" aria-label="Permalink to “2. 为什么这两个主题总会一起出现”">​</a></h2><p>因为在真实 Web 服务里，它们都属于“边界层治理”。</p><p>当请求进入系统时，你要决定：</p><ul><li>路由怎么分发</li><li>参数怎么提取</li><li>业务怎么调用</li><li>错误怎么映射</li><li>日志和 tracing 怎么加</li><li>鉴权、限流、超时、上下文信息在哪里插入</li></ul><p>这说明错误处理和中间件都不是附属细节，<br> 而是整个请求处理链路的结构问题。</p><h2 id="_3-先建立直觉" tabindex="-1">3. 先建立直觉 <a class="header-anchor" href="#_3-先建立直觉" aria-label="Permalink to “3. 先建立直觉”">​</a></h2><h3 id="_3-1-错误处理解决的是-失败如何被表达" tabindex="-1">3.1 错误处理解决的是“失败如何被表达” <a class="header-anchor" href="#_3-1-错误处理解决的是-失败如何被表达" aria-label="Permalink to “3.1 错误处理解决的是“失败如何被表达””">​</a></h3><p>失败不是只有一种。<br> 在 Web 服务里，你会碰到：</p><ul><li>参数不合法</li><li>资源不存在</li><li>权限不足</li><li>数据库失败</li><li>下游服务超时</li><li>内部未知错误</li></ul><p>真正的问题不是“会不会失败”，而是：</p><ul><li>这些失败对外应该长什么样</li><li>哪些要暴露成 4xx</li><li>哪些要暴露成 5xx</li><li>哪些细节只该写日志，不该直接返回给客户端</li></ul><h3 id="_3-2-中间件解决的是-重复横切逻辑放哪" tabindex="-1">3.2 中间件解决的是“重复横切逻辑放哪” <a class="header-anchor" href="#_3-2-中间件解决的是-重复横切逻辑放哪" aria-label="Permalink to “3.2 中间件解决的是“重复横切逻辑放哪””">​</a></h3><p>很多逻辑不是某个 handler 独有，而是很多接口都需要：</p><ul><li>请求日志</li><li>request id</li><li>tracing span</li><li>鉴权</li><li>CORS</li><li>超时</li><li>压缩</li><li>限流</li></ul><p>如果这些都写进每个 handler，代码会很快失控。<br> 所以中间件的意义就是：</p><ul><li>把这些横切能力从业务 handler 里抽出来，放到统一链路层处理</li></ul><h2 id="_4-rust-web-错误处理最核心的工程直觉" tabindex="-1">4. Rust Web 错误处理最核心的工程直觉 <a class="header-anchor" href="#_4-rust-web-错误处理最核心的工程直觉" aria-label="Permalink to “4. Rust Web 错误处理最核心的工程直觉”">​</a></h2><h3 id="_4-1-错误类型其实是在定义-http-边界语义" tabindex="-1">4.1 错误类型其实是在定义 HTTP 边界语义 <a class="header-anchor" href="#_4-1-错误类型其实是在定义-http-边界语义" aria-label="Permalink to “4.1 错误类型其实是在定义 HTTP 边界语义”">​</a></h3><p>在普通 Rust 模块里，错误类型定义模块边界。<br> 在 Web 场景里，这件事会进一步表现成：</p><ul><li>某类错误最终映射成什么 HTTP 语义</li><li>客户端能否稳定理解这个失败</li><li>内部错误细节是否被妥善隐藏</li></ul><p>所以 Web 错误处理不能只停留在“把 <code>Err</code> 传上去”，而要继续问：</p><ul><li>这个 <code>Err</code> 最后准备以什么响应形式出现</li></ul><h3 id="_4-2-对外错误语义和内部诊断信息要分层" tabindex="-1">4.2 对外错误语义和内部诊断信息要分层 <a class="header-anchor" href="#_4-2-对外错误语义和内部诊断信息要分层" aria-label="Permalink to “4.2 对外错误语义和内部诊断信息要分层”">​</a></h3><p>一个成熟服务里，错误至少有两层：</p><ul><li><strong>对外层</strong>：返回给客户端的状态码、错误码、消息</li><li><strong>对内层</strong>：日志、source chain、上下文、堆栈、调用链信息</li></ul><p>这两层不应该混在一起。</p><p>也就是说：</p><ul><li>客户端看到的错误应该稳定、清晰、可预期</li><li>开发者看到的内部信息应该足够详细、可排查</li></ul><h3 id="_4-3-统一错误出口很重要" tabindex="-1">4.3 统一错误出口很重要 <a class="header-anchor" href="#_4-3-统一错误出口很重要" aria-label="Permalink to “4.3 统一错误出口很重要”">​</a></h3><p>如果每个 handler 都各自决定怎么拼错误响应，很快就会出现：</p><ul><li>格式不统一</li><li>状态码风格混乱</li><li>前端处理成本上升</li><li>日志和错误映射重复</li></ul><p>所以真正成熟的做法往往是：</p><ul><li>让不同类型的错误在边界层统一收敛</li><li>用统一响应结构输出给客户端</li></ul><p>这样项目的错误语义才会稳定。</p><h2 id="_5-rust-web-中间件设计最核心的工程直觉" tabindex="-1">5. Rust Web 中间件设计最核心的工程直觉 <a class="header-anchor" href="#_5-rust-web-中间件设计最核心的工程直觉" aria-label="Permalink to “5. Rust Web 中间件设计最核心的工程直觉”">​</a></h2><h3 id="_5-1-中间件不是-所有公共逻辑的垃圾桶" tabindex="-1">5.1 中间件不是“所有公共逻辑的垃圾桶” <a class="header-anchor" href="#_5-1-中间件不是-所有公共逻辑的垃圾桶" aria-label="Permalink to “5.1 中间件不是“所有公共逻辑的垃圾桶””">​</a></h3><p>虽然中间件承载横切逻辑，但不代表凡是公共代码都该塞进去。<br> 更适合放进中间件的，通常是：</p><ul><li>与请求链路强相关</li><li>对多个路由统一生效</li><li>不属于某个具体业务领域</li></ul><p>比如：</p><ul><li>日志</li><li>request id</li><li>tracing span</li><li>鉴权前置检查</li><li>限流</li><li>通用 header 处理</li></ul><p>而不是：</p><ul><li>某个具体业务流程的判断分支</li><li>领域规则本身</li></ul><h3 id="_5-2-中间件本质上是在控制-请求经过系统时被怎样包裹" tabindex="-1">5.2 中间件本质上是在控制“请求经过系统时被怎样包裹” <a class="header-anchor" href="#_5-2-中间件本质上是在控制-请求经过系统时被怎样包裹" aria-label="Permalink to “5.2 中间件本质上是在控制“请求经过系统时被怎样包裹””">​</a></h3><p>你可以把中间件想成一层层包裹请求处理链路的壳。<br> 请求进入系统时：</p><ul><li>可能先经过日志记录</li><li>再经过鉴权</li><li>再经过 tracing 注入</li><li>再进入 handler</li><li>出错后再被统一映射成响应</li></ul><p>所以中间件不是“附加组件”，而是请求生命周期的一部分。</p><h3 id="_5-3-顺序非常重要" tabindex="-1">5.3 顺序非常重要 <a class="header-anchor" href="#_5-3-顺序非常重要" aria-label="Permalink to “5.3 顺序非常重要”">​</a></h3><p>中间件的执行顺序经常会直接影响行为：</p><ul><li>先打日志还是先鉴权</li><li>request id 在哪一层注入</li><li>timeout 应该包裹哪些逻辑</li><li>错误映射发生在多靠外的一层</li></ul><p>所以中间件设计不是“有没有”，而是“链路顺序是否合理”。</p><h2 id="_6-错误处理和中间件为什么要一起设计" tabindex="-1">6. 错误处理和中间件为什么要一起设计 <a class="header-anchor" href="#_6-错误处理和中间件为什么要一起设计" aria-label="Permalink to “6. 错误处理和中间件为什么要一起设计”">​</a></h2><p>因为它们常常互相配合：</p><ul><li>中间件可以注入 request id，错误响应里可能需要带上它</li><li>tracing 中间件会记录错误上下文</li><li>统一错误出口可能本身就依赖某层公共处理逻辑</li><li>鉴权中间件可能提前拦截并产出标准化错误响应</li></ul><p>也就是说，错误处理和中间件都在塑造同一件事：</p><ul><li><strong>请求进入系统后，成功和失败分别如何被组织</strong></li></ul><h2 id="_7-axum-actix-里真正该优先建立的能力" tabindex="-1">7. Axum / Actix 里真正该优先建立的能力 <a class="header-anchor" href="#_7-axum-actix-里真正该优先建立的能力" aria-label="Permalink to “7. Axum / Actix 里真正该优先建立的能力”">​</a></h2><p>不管你站在哪个框架上，先抓住这些能力最重要：</p><ol><li>统一错误响应结构</li><li>清晰区分 4xx 和 5xx</li><li>内部诊断信息不裸露给外部</li><li>日志 / tracing 放进统一链路</li><li>鉴权、限流、request id 这类横切逻辑从 handler 中抽离</li><li>保持 handler 薄、边界清晰</li></ol><p>只要这几件事做对，框架 API 细节差异反而没那么关键。</p><h2 id="_8-常见误区" tabindex="-1">8. 常见误区 <a class="header-anchor" href="#_8-常见误区" aria-label="Permalink to “8. 常见误区”">​</a></h2><h3 id="_8-1-误区一-错误处理就是返回状态码" tabindex="-1">8.1 误区一：错误处理就是返回状态码 <a class="header-anchor" href="#_8-1-误区一-错误处理就是返回状态码" aria-label="Permalink to “8.1 误区一：错误处理就是返回状态码”">​</a></h3><p>不够。<br> 状态码只是外层结果，真正重要的是错误语义是否稳定、统一、可维护。</p><h3 id="_8-2-误区二-所有公共逻辑都应该做成中间件" tabindex="-1">8.2 误区二：所有公共逻辑都应该做成中间件 <a class="header-anchor" href="#_8-2-误区二-所有公共逻辑都应该做成中间件" aria-label="Permalink to “8.2 误区二：所有公共逻辑都应该做成中间件”">​</a></h3><p>不对。<br> 只有真正的横切请求链路逻辑，才适合放进中间件。</p><h3 id="_8-3-误区三-只要能把错误打到日志里-外部响应随便点也没关系" tabindex="-1">8.3 误区三：只要能把错误打到日志里，外部响应随便点也没关系 <a class="header-anchor" href="#_8-3-误区三-只要能把错误打到日志里-外部响应随便点也没关系" aria-label="Permalink to “8.3 误区三：只要能把错误打到日志里，外部响应随便点也没关系”">​</a></h3><p>不行。<br> 客户端也需要稳定、可理解的失败语义。</p><h3 id="_8-4-误区四-中间件越多越专业" tabindex="-1">8.4 误区四：中间件越多越专业 <a class="header-anchor" href="#_8-4-误区四-中间件越多越专业" aria-label="Permalink to “8.4 误区四：中间件越多越专业”">​</a></h3><p>并不是。<br> 层次过多、顺序混乱、职责不清，反而会让链路难以理解和调试。</p><h2 id="_9-一个更实用的判断思路" tabindex="-1">9. 一个更实用的判断思路 <a class="header-anchor" href="#_9-一个更实用的判断思路" aria-label="Permalink to “9. 一个更实用的判断思路”">​</a></h2><p>当你在设计 Rust Web 的错误处理和中间件时，可以先问：</p><ol><li>这个错误是给客户端看，还是给开发者排查看</li><li>这个逻辑是某个 handler 独有，还是全链路共享</li><li>这层逻辑应该放在 handler、服务层，还是中间件层</li><li>这个中间件的位置会不会影响日志、鉴权、超时或错误映射顺序</li><li>当前设计是否让 handler 更薄、更清晰，而不是更臃肿</li></ol><h2 id="_10-建议学习顺序" tabindex="-1">10. 建议学习顺序 <a class="header-anchor" href="#_10-建议学习顺序" aria-label="Permalink to “10. 建议学习顺序”">​</a></h2><p>建议按这个顺序继续深入：</p><ol><li>先建立统一错误响应结构</li><li>再梳理 4xx / 5xx 的分类方式</li><li>再加 request id、tracing、访问日志</li><li>再抽离鉴权、限流、超时等中间件</li><li>最后统一整理错误出口、中间件顺序和项目模块结构</li></ol><h2 id="_11-自测标准" tabindex="-1">11. 自测标准 <a class="header-anchor" href="#_11-自测标准" aria-label="Permalink to “11. 自测标准”">​</a></h2><ul><li>能解释 Web 错误处理为什么不只是“返回状态码”</li><li>能知道对外错误语义与内部诊断信息应该分层</li><li>能理解中间件的本质是承载横切请求链路逻辑</li><li>能意识到中间件顺序会直接影响系统行为</li><li>能判断某段逻辑该放在 handler、服务层还是中间件层</li></ul>',84)])])}const c=i(h,[["render",t]]);export{b as __pageData,c as default};
